INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.16.265','cb','cb.adi.16','ЧБ Ади 16.265',265,'তথাপিহ হরিদাস উচ্চৈ-স্বর করি’ ।
বলেন প্রভুর সঙ্কীর্ত্তন মুখ ভরি’ ॥২৬৫॥','татха̄пиха харида̄са уччаих̣свара кари’
балена прабхура сан̇кӣртана мукха бхари’',NULL,NULL),('cb.adi.16.266','cb','cb.adi.16','ЧБ Ади 16.266',266,'ইহাতেও অত্যন্ত দুষ্কৃতি পাপীগণ ।
না পারে শুনিতে উচ্চ-হরিসঙ্কীর্ত্তন ॥২৬৬॥','иха̄те о атйанта душ̣кр̣ти па̄пи-ган̣а
на̄ па̄ре ш́уните учча-хари-сан̇кӣртана',NULL,NULL),('cb.adi.16.267','cb','cb.adi.16','ЧБ Ади 16.267',267,'হরিনদী-গ্রামে এক ব্রাহ্মণ দুর্জ্জন ।
হরিদাসে দেখি’ ক্রোধে বলয়ে বচন ॥২৬৭॥','харинадӣ-гра̄ме эка бра̄хман̣а дурджана
харида̄се декхи’ кродхе балайе вачана',NULL,NULL),('cb.adi.16.268','cb','cb.adi.16','ЧБ Ади 16.268',268,'“অয়ে হরিদাস! একি ব্যভার তোমার ।
ডাকিয়া যে নাম লহ, কি হেতু ইহার? ॥২৬৮॥','‘айе харида̄са! э ки вйабха̄ра тома̄ра
д̣а̄кийа̄ йе на̄ма лаха, ки хету иха̄ра?',NULL,NULL),('cb.adi.16.269','cb','cb.adi.16','ЧБ Ади 16.269',269,'মনে মনে জপিবা,—এই সে ধর্ম্ম হয় ।
ডাকিয়া লৈতে নাম কোন্ শাস্ত্রে কয়? ॥২৬৯॥','мане мане джапиба̄, — эи се дхарма хайа
д̣а̄дийа̄ лаите на̄ма кон ш́а̄стре кайа?',NULL,NULL),('cb.adi.16.270','cb','cb.adi.16','ЧБ Ади 16.270',270,'কার শিক্ষা,—হরিনাম ডাকিয়া লইতে? ।
এই ত’ পণ্ডিত-সভা, বলহ ইহাতে” ॥২৭০॥','ка̄’ра ш́икш̣а̄, — хари-на̄ма д̣а̄кийа̄ лаите?
эи та’ пан̣д̣ита-сабха̄, балаха иха̄те’',NULL,NULL),('cb.adi.16.271','cb','cb.adi.16','ЧБ Ади 16.271',271,'হরিদাস বলেন,—“ইহার যত তত্ত্ব ।
তোমরা সে জান’ হরিনামের মহত্ত্ব ॥২৭১॥','харида̄са балена, — ‘иха̄ра йата таттва
томара̄ се джа̄на’ хари-на̄мера махаттва',NULL,NULL),('cb.adi.16.272','cb','cb.adi.16','ЧБ Ади 16.272',272,'তোমরা-সবার মুখে শুনিঞা সে আমি ।
বলিতেছি, বলিবাঙ যেবা কিছু জানি ॥২৭২॥','томара̄-саба̄ра мукхе ш́унин̃а̄ се а̄ми
балитечхи, балиба̄н̇а йеба̄ кичху джа̄ни',NULL,NULL),('cb.adi.16.273','cb','cb.adi.16','ЧБ Ади 16.273',273,'উচ্চ করি’ লৈলে শতগুণ পূণ্য হয় ।
দোষ ত’ না কহে শাস্ত্রে, গুণ সে বর্ণয়” ॥২৭৩॥','учча кари’ лаиле ш́ата-гун̣а пун̣йа хайа
дош̣а та’ на̄ кахе ш́а̄стре, гун̣а се варн̣ана’',NULL,NULL),('cb.adi.16.274','cb','cb.adi.16','ЧБ Ади 16.274',274,'“উচ্চৈঃ শতগুণং ভবেৎ” ইতি ॥২৭৪॥','уччаих̣ ш́ата-гун̣ам̇ бхавет',NULL,NULL),('cb.adi.16.275','cb','cb.adi.16','ЧБ Ади 16.275',275,'বিপ্র বলে,—“উচ্চ-নাম করিলে উচ্চার ।
শতগুণ পুণ্যফল হয়, কি হেতু ইহার?” ॥২৭৫॥','випра бале, — ‘учча-на̄ма кариле учча̄ра
ш́ата-гун̣а пун̣йа-пхала хайа, ки хету иха̄ра?’',NULL,NULL),('cb.adi.16.276','cb','cb.adi.16','ЧБ Ади 16.276',276,'হরিদাস বলেন,—“শুনহ, মহাশয় ! ।
যে তত্ত্ব ইহার, বেদে ভাগবতে কয়” ॥২৭৬॥','харида̄са балена, — ‘ш́унаха, маха̄ш́айа!
йе таттва иха̄ра, веде бха̄гйавате кайа’',NULL,NULL),('cb.adi.16.277','cb','cb.adi.16','ЧБ Ади 16.277',277,'সর্ব্বশাস্ত্র স্ফুরে হরিদাসের শ্রীমুখে ।
লাগিলা করিতে ব্যাখ্যা কৃষ্ণানন্দ-সুখে ॥২৭৭॥','сарва-ш́а̄стра спхуре харида̄сера ш́рӣ-мукхе
ла̄гила̄ карите вйа̄кхйа̄ кр̣ш̣н̣а̄нанда сукхе',NULL,NULL),('cb.adi.16.278','cb','cb.adi.16','ЧБ Ади 16.278',278,'“শুন বিপ্র ! সকৃৎ শুনিলে কৃষ্ণনাম ।
পশু, পক্ষী, কীট যায় শ্রীবৈকুণ্ঠ-ধাম ॥২৭৮॥','‘ш́уна, вирпа! ш́акр̣т ш́униле кр̣ш̣н̣а-на̄ма
паш́у, пакш̣ӣ, кӣт̣а йа̄йа ш́рӣ-ваикун̣т̣ха-дха̄ма',NULL,NULL),('cb.adi.16.279','cb','cb.adi.16','ЧБ Ади 16.279',279,'যন্নাম গৃহ্ণন্নখিলান্ শ্রোতৄনাত্মানমেব চ ।
সদ্যঃ পুনাতি কিং ভূয়স্তস্য স্পৃষ্টঃ পদা হি তে ॥২৭৯॥','йан-на̄ма гр̣хн̣анн акхила̄м
ш́ротр̣̃н а̄тма̄нам эва ча
садйах̣ пуна̄ти ким̇ бхӯйас
тасйа спр̣ш̣т̣ах̣ пада̄ хи те',NULL,NULL),('cb.adi.16.280','cb','cb.adi.16','ЧБ Ади 16.280',280,'পশু-পক্ষী-কীট-আদি বলিতে না পারে ।
শুনিলেই হরিনাম তারা সব তরে’ ॥২৮০॥','паш́у-пакш̣ӣ-кӣт̣а-а̄ди балите на̄ па̄ре
ш́унилеи хари-на̄ма та̄’ра̄саба таре’',NULL,NULL),('cb.adi.16.281','cb','cb.adi.16','ЧБ Ади 16.281',281,'জপিলে শ্রীকৃষ্ণনাম আপনে সে তরে ।
উচ্চ-সঙ্কীর্ত্তনে পর-উপকার করে ॥২৮১॥','джапиле ш́рӣ-кр̣ш̣н̣а-на̄ма а̄пане се таре
учча-сан̇кӣртане пара упака̄ра каре',NULL,NULL),('cb.adi.16.282','cb','cb.adi.16','ЧБ Ади 16.282',282,'অতএব উচ্চ করি’ কীর্ত্তন করিলে ।
শতগুণ ফল হয় সর্ব্বশাস্ত্রে বলে ॥২৮২॥','атаева учча кари’ кӣртана кариле
ш́ата-гун̣а пхала хайа сарва-ш́а̄стре бале',NULL,NULL),('cb.adi.16.283','cb','cb.adi.16','ЧБ Ади 16.283',283,'জপতো হরিনামানি স্থানে শতগুণাধিকঃ ।
আত্মানঞ্চ পুনাত্যুচ্চৈর্জপন্ শ্রোতৄন্ পুনাতি চ ॥২৮৩॥','джапато хари-на̄ма̄ни стха̄не ш́ата-гун̣а̄дхиках̣
а̄тма̄нам̇ ча пуна̄тй уччаир джапан ш́ротр̣н пуна̄ти ча',NULL,NULL),('cb.adi.16.284','cb','cb.adi.16','ЧБ Ади 16.284',284,'জপকর্ত্তা হৈতে উচ্চসঙ্কীর্ত্তনকারী ।
শতগুণ অধিক সে পুরাণেতে ধরি ॥২৮৪॥','джапа-карта̄ хаите учча-сан̇кӣртана-ка̄рӣ
ш́ата-гун̣а адхика се пура̄н̣ете дхари',NULL,NULL),('cb.adi.16.285','cb','cb.adi.16','ЧБ Ади 16.285',285,'শুন, বিপ্র ! মন দিয়া ইহার কারণ ।
জপি’ আপনারে সবে করয়ে পোষণ ॥২৮৫॥','ш́уна, випра! мана дийа̄ иха̄ра ка̄ран̣а
джапи’ а̄пана̄ре сабе карайе пош̣ан̣а',NULL,NULL),('cb.adi.16.286','cb','cb.adi.16','ЧБ Ади 16.286',286,'উচ্চ করি’ করিলে গোবিন্দ-সঙ্কীর্ত্তন ।
জন্তুমাত্র শুনিঞাই পাই বিমোচন ॥২৮৬॥','учча кари’ кариле говинда-сан̇кӣртана
джанту-ма̄тра ш́унин̃а̄и па̄и вимочана',NULL,NULL),('cb.adi.16.287','cb','cb.adi.16','ЧБ Ади 16.287',287,'জিহ্বা পাইঞাও নর-বিনা সর্ব্ব-প্রাণী ।
না পারে বলিতে কৃষ্ণনাম-হেন ধ্বনি ॥২৮৭॥','джихва̄ па̄ин̃а̄о нара-вина̄ сарва-пра̄н̣ӣ
на̄ па̄ре балите кр̣ш̣н̣а-на̄ма-хена дхвани',NULL,NULL),('cb.adi.16.288','cb','cb.adi.16','ЧБ Ади 16.288',288,'ব্যর্থজন্মা ইহারা নিস্তরে যাহা হৈতে ।
বল দেখি,—কোন্ দোষ সে কর্ম্ম করিতে? ॥২৮৮॥','вйартха-джанма иха̄ра̄ нистаре йа̄ха̄ хаите
бала декхи, — кон дош̣а се карма карите?',NULL,NULL),('cb.adi.16.289','cb','cb.adi.16','ЧБ Ади 16.289',289,'কেহ আপনারে মাত্র করয়ে পোষণ ।
কেহ বা পোষণ করে সহস্রেক জন ॥২৮৯॥','кеха а̄пана̄ре ма̄тра карайе пош̣ан̣а
кеха ва̄ пош̣ан̣а каре сахасрека джана',NULL,NULL),('cb.adi.16.290','cb','cb.adi.16','ЧБ Ади 16.290',290,'দুইতে কে বড়, ভাবি’ বুঝহ আপনে ।
এই অভিপ্রায় গুণ’ উচ্চসঙ্কীর্ত্তনে” ॥২৯০॥','дуите ке бад̣а, бха̄ви’ буджхала а̄пане
эи абхипра̄йа гун̣а’ учча-сан̇кӣртане’',NULL,NULL),('cb.adi.16.291','cb','cb.adi.16','ЧБ Ади 16.291',291,'সেই বিপ্র শুনি’ হরিদাসের কথন ।
বলিতে লাগিল ক্রোধে মহা-দুর্ব্বচন ॥২৯১॥','сеи випра ш́уни’ харида̄сера катхана
балите ла̄гила кродхе маха̄-дурвачана',NULL,NULL),('cb.adi.16.292','cb','cb.adi.16','ЧБ Ади 16.292',292,'“দরশনকর্ত্তা এবে হৈল হরিদাস ! ।
কালে-কালে বেদপথ হয় দেখি’ নাশ ॥২৯২॥','‘дараш́ана-карта̄ эбе хаила харида̄са!
ка̄ле-ка̄ле веда-патха хайа декхи на̄ш́а',NULL,NULL),('cb.adi.16.293','cb','cb.adi.16','ЧБ Ади 16.293',293,'‘যুগশেষে শূদ্র বেদ করিবে বাখানে’।
এখনই তাহা দেখি, শেষে আর কেনে? ॥২৯৩॥','йуга-ш́еш̣е ш́ӯдра веда карибе ва̄кха̄не
экханаи та̄ха̄ декхи, ш́еш̣е а̄ра кене?',NULL,NULL),('cb.adi.16.294','cb','cb.adi.16','ЧБ Ади 16.294',294,'এইরূপে আপনারে প্রকট করিয়া ।
ঘরে-ঘরে ভাল ভোগ খাইস্ বুলিয়া ॥২৯৪॥','эи-рӯпе а̄пана̄ре пракат̣а карийа̄
гхаре-гхаре бха̄ла бхога кха̄ис булийа̄',NULL,NULL),('cb.adi.16.295','cb','cb.adi.16','ЧБ Ади 16.295',295,'যে ব্যাখ্যা করিলি তুই, এ যদি না লাগে ।
তবে তোর নাক কাণ কাটি’ তোর আগে” ॥২৯৫॥','йе вйа̄кхйа̄ кариле туи, э йади на̄ ла̄ге
табе тора на̄ка ка̄н̣а ка̄т̣и’ тора а̄ге’',NULL,NULL),('cb.adi.16.296','cb','cb.adi.16','ЧБ Ади 16.296',296,'শুনি’ বিপ্রাধমের বচন হরিদাস ।
‘হরি’ বলি’ ঈষৎ হইল কিছু হাস ॥২৯৬॥','ш́уни’ випра̄дхамера вачана харида̄са
‘хари’ бали’ ӣш̣ат хаила кичху ха̄са',NULL,NULL),('cb.adi.16.297','cb','cb.adi.16','ЧБ Ади 16.297',297,'প্রত্যুত্তর আর কিছু তারে না করিয়া ।
চলিলেন উচ্চ করি’ কীর্ত্তন গাইয়া ॥২৯৭॥','пратйуттара а̄ра кичху та̄ре на̄ карийа̄
чалилена учча кари’ кӣртана га̄ийа̄',NULL,NULL),('cb.adi.16.298','cb','cb.adi.16','ЧБ Ади 16.298',298,'যেবা পাপী সভাসদ, সেহ পাপমতি ।
উচিত উত্তর কিছু না করিল ইথি ॥২৯৮॥','йеба̄ па̄пӣ сабха̄сад, сеха па̄па-мати
учита уттара кичху на̄ карила итхи',NULL,NULL),('cb.adi.16.299','cb','cb.adi.16','ЧБ Ади 16.299',299,'এ সকল রাক্ষস, ব্রাহ্মণ নাম মাত্র ।
এইসব লোক যম-যাতনার পাত্র ॥২৯৯॥','э сакала ра̄кш̣аса, бра̄хман̣а на̄ма ма̄тра
эи-саба лока йама-йа̄тана̄ра па̄тра',NULL,NULL),('cb.adi.16.300','cb','cb.adi.16','ЧБ Ади 16.300',300,'কলিযুগে রাক্ষস-সকল বিপ্র-ঘরে ।
জন্মিবেক সুজনের হিংসা করিবারে ॥৩০০॥','кали-йуге ра̄кш̣аса-сакала випра-гхаре
джанмибека суджанера хим̇са̄ кариба̄ре',NULL,NULL),('cb.adi.16.301','cb','cb.adi.16','ЧБ Ади 16.301',301,'রাক্ষসাঃ কলিমাশ্রিত্য জায়ন্তে ব্রহ্মযোনিষু ।
উৎপন্না ব্রাহ্মণকুলে বাধন্তে শ্রোত্রিয়ান্ কৃশান্ ॥৩০১॥','ра̄кш̣аса̄х̣ калим а̄ш́рӣтйа
джа̄йанте брахма-йониш̣у
утпанна̄ бра̄хман̣а-куле
ба̄дханте ш́ротрийа̄н кр̣ш́а̄н',NULL,NULL),('cb.adi.16.302','cb','cb.adi.16','ЧБ Ади 16.302',302,'এ সব বিপ্রের স্পর্শ, কথা, নমস্কার ।
ধর্ম্মশাস্ত্রে সর্ব্বথা নিষেধ করিবার ॥৩০২॥','э саба випрера спарш́а, катха̄, намаска̄ра
дхарма-ш́а̄стре сарватха̄ ниш̣едха кариба̄ра',NULL,NULL),('cb.adi.16.303','cb','cb.adi.16','ЧБ Ади 16.303',303,'কিমত্র বহুনোক্তেন ব্রাহ্মণা যে হ্যবৈষ্ণবাঃ ।
তেষাং সম্ভাষণং স্পর্শং প্রমাদেনাপি বর্জ্জয়েৎ ॥৩০৩॥','бра̄хман̣а̄ йе хй аваиш̣н̣ава̄х̣
теш̣а̄м̇ самбха̄ш̣ан̣ам̇ спарш́ам̇
